class Solution:
    def countCoveredBuildings(self, n, buildings):
        pts = set((x, y) for x, y in buildings)
        cnt = 0
        for (x, y) in pts:
            left = any(px == x and py < y for (px, py) in pts)
            right = any(px == x and py > y for (px, py) in pts)
            up = any(py == y and px < x for (px, py) in pts)
            down = any(py == y and px > x for (px, py) in pts)
            if left and right and up and down:
                cnt += 1
        return cnt

